function dateMonths(start,end){
  const out=[];
  const s=start?new Date(start+'T00:00:00Z'):new Date();
  const e=end?new Date(end+'T00:00:00Z'):new Date();
  let y=s.getUTCFullYear();
  let m=s.getUTCMonth();
  const ey=e.getUTCFullYear();
  const em=e.getUTCMonth();
  while(y<ey||(y===ey&&m<=em)){
    out.push(String(m+1).padStart(2,'0')+'/%/'+y);
    m++;
    if(m>11){m=0;y++;}
  }
  return out.length?out:[String((new Date()).getUTCMonth()+1).padStart(2,'0')+'/%/'+(new Date()).getUTCFullYear()];
}

