function buildDavieUrl(source, offset){
  const base=(source.source_url||'').split('?')[0];
  const whereParts=[];
  const propType=(d.property_type||'').toLowerCase();
  const months=[];
  const s=d.date_range_start?new Date(d.date_range_start+'T00:00:00Z'):new Date();
  const e=d.date_range_end?new Date(d.date_range_end+'T00:00:00Z'):new Date();
  let y=s.getUTCFullYear();
  let m=s.getUTCMonth()+1;
  const ey=e.getUTCFullYear();
  const em=e.getUTCMonth()+1;
  while(y<ey||(y===ey&&m<=em)){
    months.push('(saleyear = '+y+' AND salemonth = '+m+')');
    m++;
    if(m>12){m=1;y++;}
